// 改行あり
System.out.println("Hello");
System.out.println("World");
// 出力: Hello
//       World

// 改行なし
System.out.print("Hello");
System.out.print("World");
// 出力: HelloWorld

// 書式指定
System.out.printf("名前は%sです。年齢は%d歳です。", "太郎", 20);
// 出力: 名前は太郎です。年齢は20歳です。

// \n → 改行
System.out.println("Hello\nWorld");
// 出力: Hello
//       World

// \t → タブ（字下げ）
System.out.println("名前\t年齢");
System.out.println("太郎\t20");
// 出力: 名前	年齢
//       太郎	20

// \\ → バックスラッシュ自身
System.out.println("C:\\Users\\");
// 出力: C:\Users\

// \" → ダブルクォート
System.out.println("彼は\"Java\"が好きです");
// 出力: 彼は"Java"が好きです

int price = 1980;
double tax = 1.10;
System.out.printf("商品価格: %d円%n", price);
System.out.printf("税込価格: %.0f円%n", price * tax);
// 出力: 商品価格: 1980円
//       税込価格: 2178円

// 宣言と代入を別々に
int age;        // 宣言（int型の変数ageを作る）
age = 25;       // 代入（ageに25を入れる）

// 初期化（宣言と代入を同時に）
String name = "太郎";
double height = 170.5;

// 変数の値を表示
System.out.println(name);   // 太郎
System.out.println(age);    // 25

// 変数の宣言と初期化
int a = 10;
int b = 3;

System.out.println(a + b);  // 13（足し算）
System.out.println(a - b);  // 7 （引き算）
System.out.println(a * b);  // 30（掛け算）
System.out.println(a / b);  // 3 （割り算・整数同士は小数切捨て）
System.out.println(a % b);  // 1 （余り）

