// 変数の宣言と初期化
String first = "Java";
String second = "Pro";
String app = first + " " + second;
System.out.println(app);  // Java Pro

// 数値と文字列の結合
int age = 20;
System.out.println("年齢は" + age + "歳");  // 年齢は20歳

// 変数の宣言と初期化
String s = "Hello, Java!";

s.length()          // 12（文字数）
s.charAt(0)         // 'H'（0番目の文字）
s.contains("Java")  // true（含むか判定）
s.toUpperCase()     // "HELLO, JAVA!"
s.toLowerCase()     // "hello, java!"
s.replace("Java", "World")  // "Hello, World!"

// 文字列の比較は equals() を使う
String a = "abc";
String b = "abc";
a.equals(b)  // true ✓
// a == b は参照の比較なので使わない ✗

String s = "Hello, Java!";

// indexOf: 文字列の位置を検索（見つからなければ-1）
s.indexOf("Java")     // 7
s.indexOf("Python")   // -1

// substring: 文字列の一部を切り出し
s.substring(7)        // "Java!"（7番目以降）
s.substring(0, 5)     // "Hello"（0〜4番目）

// trim: 前後の空白を除去
"  Hello  ".trim()    // "Hello"

// startsWith / endsWith: 先頭・末尾の判定
s.startsWith("Hello") // true
s.endsWith("!")       // true

// isEmpty / isBlank（Java 11以降）
"".isEmpty()           // true
"  ".isEmpty()         // false
"  ".isBlank()         // true（空白のみ）

int i = 100;
double d = i;  // int → double は自動変換OK
System.out.println(d);  // 100.0

// 小さい型 → 大きい型の順
// byte → short → int → long → float → double

double d = 3.14;
int i = (int) d;  // キャスト: double → int
System.out.println(i);  // 3（小数点以下は切り捨て）

// 文字列 → 数値の変換
String numStr = "123";
int num = Integer.parseInt(numStr);  // 123
double dbl = Double.parseDouble("3.14"); // 3.14

// 数値 → 文字列の変換
String s = String.valueOf(100);  // "100"

